const r = await tools.exec_command({"cmd":"trace_path=$(find /app/sgl-profile-results -type f -name '*.trace.json.gz' | sort | tail -1)
python3 - "$trace_path" <<'PY'
import gzip,json,sys,collections,statistics
p=sys.argv[1]
with gzip.open(p,'rt') as f: e=json.load(f)['traceEvents']

def X(x): return x.get('ph')=='X' and isinstance(x.get('ts'),(int,float)) and isinstance(x.get('dur'),(int,float))
ks=[x for x in e if x.get('cat')=='kernel' and X(x)]
print('Kernel stream inventory: pid,tid,count,sum_ms,span_ms,first,last')
by=collections.defaultdict(list)
for x in ks: by[(x.get('pid'),x.get('tid'))].append(x)
for k,es in sorted(by.items(),key=lambda z:sum(x['dur'] for x in z[1]), reverse=True):
 s=min(x['ts'] for x in es); end=max(x['ts']+x['dur'] for x in es)
 print(k,len(es),round(sum(x['dur'] for x in es)/1000,3),round((end-s)/1000,3),round(s,3),round(end,3))
print('\nMemcpy categories')
ms=[x for x in e if x.get('cat')=='gpu_memcpy' and X(x)]
for k,es in sorted(collections.defaultdict(list,((x.get('args',{}).get('kind','?'),[]) for x in [])).items()):pass
bykind=collections.defaultdict(list)
for x in ms: bykind[(x.get('name'),x.get('args',{}).get('kind'),x.get('tid'))].append(x)
for k,es in sorted(bykind.items(),key=lambda z:(z[0][1],-len(z[1]))):
 print(k,'n=',len(es),'dur_us=',round(sum(x['dur'] for x in es),1),'bytes=',sum(x.get('args',{}).get('bytes',0) or 0),'correlations first=',[x.get('args',{}).get('correlation') for x in es[:8]])
print('\nCPU/cuda events matching DtoH correlations')
dtoh=[x for x in ms if x.get('args',{}).get('kind')=='DtoH']
cs={x.get('args',{}).get('correlation') for x in dtoh}
for x in e:
 if x.get('args',{}).get('correlation') in cs:
  print({k:x.get(k) for k in ('name','cat','ph','ts','dur','pid','tid')},'args=',x.get('args',{}))
print('\nTop cpu ops broadly with DtoH-ish names')
c=collections.Counter()
dur=collections.Counter()
for x in e:
 if x.get('cat') in ('cpu_op','cuda_runtime') and X(x):
  name=x.get('name')
  if any(q in str(name).lower() for q in ('item','scalar','memcpy','synchron')):
   c[(x.get('cat'),name)]+=1; dur[(x.get('cat'),name)]+=x['dur']
for k,n in c.most_common(40): print(k,n,round(dur[k]/1000,3),'ms')
