with gzip.open(sys.argv[1],'rt') as f:e=json.load(f)['traceEvents']
def X(x):return x.get('ph')=='X' and 'ts' in x and 'dur' in x
for target in [1475388513479.682,1475388513950.032]:
 print('\nTARGET',target)
 xs=[x for x in e if x.get('cat')=='python_function' and X(x) and x['ts']<=target<=x['ts']+x['dur']]
 xs.sort(key=lambda x:x['dur'],reverse=True)
 for x in xs[-22:]:print(round(x['dur'],3),x['name'])
 ops=[x for x in e if x.get('cat') in ('cpu_op','cuda_runtime') and X(x) and x['ts']<=target<=x['ts']+x['dur']]
 print('Ops');
 for x in ops: print(x['cat'],round(x['dur'],3),x['name'],x.get('args',{}))
